class Solution:
    def minTime(self, n, edges):
        from collections import defaultdict
        g = defaultdict(list)
        for u, v, s, e in edges:
            g[u].append((v, s, e))
        INF = float('inf')
        dist = [INF] * n
        dist[0] = 0
        for _ in range(n):
            changed = False
            for u in range(n):
                if dist[u] == INF:
                    continue
                for v, s, e in g[u]:
                    dep = max(dist[u], s)
                    if dep <= e and dep + 1 < dist[v]:
                        dist[v] = dep + 1
                        changed = True
            if not changed:
                break
        return dist[n - 1] if dist[n - 1] != INF else -1

