class Solution:
    def minTime(self, n, edges):
        from collections import defaultdict
        import heapq
        g = defaultdict(list)
        for u, v, s, e in edges:
            g[u].append((v, s, e))
        INF = float('inf')
        dist = [INF] * n
        dist[0] = 0
        pq = [(0, 0)]
        while pq:
            t, u = heapq.heappop(pq)
            if t > dist[u]:
                continue
            if u == n - 1:
                return t
            for v, s, e in g[u]:
                dep = max(t, s)
                if dep <= e:
                    nt = dep + 1
                    if nt < dist[v]:
                        dist[v] = nt
                        heapq.heappush(pq, (nt, v))
        return dist[n - 1] if dist[n - 1] != INF else -1

