var minTime = function(n, edges) {
    const g = Array.from({ length: n }, () => []);
    for (const [u, v, s, e] of edges) g[u].push([v, s, e]);
    const INF = Infinity;
    const dist = new Array(n).fill(INF);
    dist[0] = 0;
    const pq = [[0, 0]];
    const push = (item) => {
        pq.push(item);
        let i = pq.length - 1;
        while (i > 0) {
            const p = (i - 1) >> 1;
            if (pq[p][0] <= pq[i][0]) break;
            [pq[p], pq[i]] = [pq[i], pq[p]]; i = p;
        }
    };
    const pop = () => {
        const top = pq[0]; const last = pq.pop();
        if (pq.length) { pq[0] = last; let i = 0; const m = pq.length;
            while (true) { let l = 2*i+1, r = 2*i+2, sm = i;
                if (l < m && pq[l][0] < pq[sm][0]) sm = l;
                if (r < m && pq[r][0] < pq[sm][0]) sm = r;
                if (sm === i) break; [pq[sm], pq[i]] = [pq[i], pq[sm]]; i = sm; } }
        return top;
    };
    while (pq.length) {
        const [t, u] = pop();
        if (t > dist[u]) continue;
        if (u === n - 1) return t;
        for (const [v, s, e] of g[u]) {
            const dep = Math.max(t, s);
            if (dep <= e) {
                const nt = dep + 1;
                if (nt < dist[v]) { dist[v] = nt; push([nt, v]); }
            }
        }
    }
    return dist[n - 1] !== INF ? dist[n - 1] : -1;
};
